func TestDecoderPreservesDefaultsWithNullNode(t *testing.T) {
	type Default struct {
		Key string `yaml:"key"`
	}

	type Test struct {
		First    string  `yaml:"first"`
		Defaults Default `yaml:"second"`
	}

	// Case 1: Nested struct with null value and comments
	test := Test{Defaults: Default{Key: "My default Value"}}
	if err := yaml.Unmarshal([]byte(`first: "Test"
second:
  # Just want to document the fields of the nested struct
#  key: "Value from YAML"
`), &test); err != nil {
		t.Fatalf("failed to unmarshal: %v", err)
	}
	if test.Defaults.Key != "My default Value" {
		t.Fatalf("expected default value to be preserved, got %q", test.Defaults.Key)
	}

	// Case 2: Nested struct with explicit null value
	test2 := Test{Defaults: Default{Key: "My default Value"}}
	if err := yaml.Unmarshal([]byte(`first: "Test"
second: null
`), &test2); err != nil {
		t.Fatalf("failed to unmarshal: %v", err)
	}
	if test2.Defaults.Key != "My default Value" {
		t.Fatalf("expected default value to be preserved with explicit null, got %q", test2.Defaults.Key)
	}

	// Case 3: Nested struct with empty mapping
	test3 := Test{Defaults: Default{Key: "My default Value"}}
	if err := yaml.Unmarshal([]byte(`first: "Test"
second: {}
`), &test3); err != nil {
		t.Fatalf("failed to unmarshal: %v", err)
	}
	if test3.Defaults.Key != "My default Value" {
		t.Fatalf("expected default value to be preserved with empty mapping, got %q", test3.Defaults.Key)
	}

	// Case 4: Nested struct with actual value (should override)
	test4 := Test{Defaults: Default{Key: "My default Value"}}
	if err := yaml.Unmarshal([]byte(`first: "Test"
second:
  key: "Value from YAML"
`), &test4); err != nil {
		t.Fatalf("failed to unmarshal: %v", err)
	}
	if test4.Defaults.Key != "Value from YAML" {
		t.Fatalf("expected YAML value to override default, got %q", test4.Defaults.Key)
	}
}

